30	    var log = logger.Log.init(default_allocator);
31	    defer log.deinit();
32	    const input_value = callframe.argument(0);
33	    if (input_value.isEmptyOrUndefinedOrNull()) {
34	        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
35	    }
36	
37	    var input_slice = try input_value.toSlice(globalThis, bun.default_allocator);
