1	/**
2	 * Bun.js runtime APIs
3	 *
4	 * @example
5	 *
6	 * ```js
7	 * import {file} from 'bun';
8	 *
9	 * // Log the file to the console
10	 * const input = await file('/path/to/file.txt').text();
11	 * console.log(input);
12	 * ```
13	 *
14	 * This module aliases `globalThis.Bun`.
15	 */
16	declare module "bun" {
17	  type PathLike = string | NodeJS.TypedArray | ArrayBufferLike | URL;
18	  type ArrayBufferView<TArrayBuffer extends ArrayBufferLike = ArrayBufferLike> =
19	    | NodeJS.TypedArray<TArrayBuffer>
20	    | DataView<TArrayBuffer>;
21	  type BufferSource = NodeJS.TypedArray<ArrayBufferLike> | DataView<ArrayBufferLike> | ArrayBufferLike;
22	  type StringOrBuffer = string | NodeJS.TypedArray | ArrayBufferLike;
23	  type XMLHttpRequestBodyInit = Blob | BufferSource | FormData | URLSearchParams | string;
24	  type ReadableStreamController<T> = ReadableStreamDefaultController<T>;
25	  type ReadableStreamDefaultReadResult<T> =
26	    | ReadableStreamDefaultReadValueResult<T>
27	    | ReadableStreamDefaultReadDoneResult;
28	  type ReadableStreamReader<T> = ReadableStreamDefaultReader<T>;
29	  type Transferable = ArrayBuffer | MessagePort;
30	  type MessageEventSource = Bun.__internal.UseLibDomIfAvailable<"MessageEventSource", undefined>;
31	  type Encoding = "utf-8" | "windows-1252" | "utf-16";
32	  type UncaughtExceptionOrigin = "uncaughtException" | "unhandledRejection";
33	  type MultipleResolveType = "resolve" | "reject";
34	  type BeforeExitListener = (code: number) => void;
35	  type DisconnectListener = () => void;
36	  type ExitListener = (code: number) => void;
