49	  namespace __internal {
50	    type LibDomIsLoaded = typeof globalThis extends { onabort: any } ? true : false;
51	
52	    /**
53	     * Helper type for avoiding conflicts in types.
54	     *
55	     * Uses the lib.dom.d.ts definition if it exists, otherwise defines it locally.
56	     *
57	     * This is to avoid type conflicts between lib.dom.d.ts and \@types/bun.
58	     *
59	     * Unfortunately some symbols cannot be defined when both Bun types and lib.dom.d.ts types are loaded,
60	     * and since we can't redeclare the symbol in a way that satisfies both, we need to fallback
61	     * to the type that lib.dom.d.ts provides.
62	     */
63	    type UseLibDomIfAvailable<GlobalThisKeyName extends PropertyKey, Otherwise> =
64	      // `onabort` is defined in lib.dom.d.ts, so we can check to see if lib dom is loaded by checking if `onabort` is defined
65	      LibDomIsLoaded extends true
66	        ? typeof globalThis extends { [K in GlobalThisKeyName]: infer T } // if it is loaded, infer it from `globalThis` and use that value
67	          ? T
68	          : Otherwise // Not defined in lib dom (or anywhere else), so no conflict. We can safely use our own definition
69	        : Otherwise; // Lib dom not loaded anyway, so no conflict. We can safely use our own definition
70	
71	    /**
72	     * Like Omit, but correctly distributes over unions. Most useful for removing
73	     * properties from union options objects, like {@link Bun.SQL.Options}
74	     *
75	     * @example
76	     * ```ts
77	     * type X = Bun.DistributedOmit<{type?: 'a', url?: string} | {type?: 'b', flag?: boolean}, "url">
78	     * // `{type?: 'a'} | {type?: 'b', flag?: boolean}` (Omit applied to each union item instead of entire type)
79	     *
80	     * type X = Omit<{type?: 'a', url?: string} | {type?: 'b', flag?: boolean}, "url">;
81	     * // `{type?: "a" | "b" | undefined}` (Missing `flag` property and no longer a union)
82	     * ```
83	     */
84	    type DistributedOmit<T, K extends PropertyKey> = T extends T ? Omit<T, K> : never;
85	
86	    type KeysInBoth<A, B> = Extract<keyof A, keyof B>;
87	    type MergeInner<A, B> = Omit<A, KeysInBoth<A, B>> &
88	      Omit<B, KeysInBoth<A, B>> & {
89	        [Key in KeysInBoth<A, B>]: A[Key] | B[Key];
90	      };
91	    type Merge<A, B> = MergeInner<A, B> & MergeInner<B, A>;
92	    type DistributedMerge<T, Else = T> = T extends T ? Merge<T, Exclude<Else, T>> : never;
93	
94	    type Without<A, B> = A & {
95	      [Key in Exclude<keyof B, keyof A>]?: never;
96	    };
97	
98	    type XOR<A, B> = Without<A, B> | Without<B, A>;
99	  }
