782	                0x00...0x1f,
783	                0x22,
784	                0x7f,
785	                0x85,
786	                0xa0,
787	                0xa8,
788	                0xa9,
789	                => return true,
790	
791	                else => {
792	                    i += 1;
793	                },
794	            }
795	        }
796	
797	        return false;
798	    }
