pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const arguments = callframe.argumentsAsArray(1);
    const input_value = arguments[0];

    if (input_value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    var input_slice = try input_value.toSlice(globalThis, bun.default_allocator);
    defer input_slice.deinit();

    const input = input_slice.slice();

    // Create result object
    const result = JSValue.createEmptyObject(globalThis, 0);

    // Current section object — starts as the root result object
    var current_section = result;

    var line_iter = std.mem.splitScalar(u8, input, '\n');
    var line_number: u32 = 0;
    while (line_iter.next()) |raw_line| {
        line_number += 1;

        // Strip trailing \r for Windows line endings
        const line_no_cr = if (raw_line.len > 0 and raw_line[raw_line.len - 1] == '\r')
            raw_line[0 .. raw_line.len - 1]
        else
            raw_line;

        const line = bun.strings.trim(line_no_cr, " \t");

        // Skip empty lines and comments
        if (line.len == 0) continue;
        if (line[0] == ';' or line[0] == '#') continue;

        // Section header: [section]
        if (line[0] == '[') {
            const end = std.mem.indexOfScalar(u8, line, ']') orelse {
                return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                    "INI Parse error: Unterminated section header on line {d}",
                    .{line_number},
                ));
            };
            const section_name = bun.strings.trim(line[1..end], " \t");
            if (section_name.len == 0) {
                return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                    "INI Parse error: Empty section name on line {d}",
                    .{line_number},
                ));
            }

            // Create section object and set it on the result
            const section_obj = JSValue.createEmptyObject(globalThis, 0);
            result.put(
                globalThis,
                bun.String.createUTF8ForJS(globalThis, section_name),
                section_obj,
            );
            current_section = section_obj;
            continue;
        }

        // Key = Value pair
        const eq_pos = std.mem.indexOfScalar(u8, line, '=') orelse {
            return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                "INI Parse error: Expected '=' on line {d}",
                .{line_number},
            ));
        };

        const key = bun.strings.trim(line[0..eq_pos], " \t");
        if (key.len == 0) {
            return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                "INI Parse error: Empty key on line {d}",
                .{line_number},
            ));
        }

        const raw_value = bun.strings.trim(line[eq_pos + 1 ..], " \t");

        // Strip inline comments (only if preceded by whitespace)
        const value_str = stripInlineComment(raw_value);

        // Coerce value types
        const js_value = coerceValue(globalThis, value_str);

        current_section.put(
            globalThis,
            bun.String.createUTF8ForJS(globalThis, key),
            js_value,
        );
    }

    return result;
}

fn stripInlineComment(value: []const u8) []const u8 {
    // Look for ; or # preceded by whitespace — that starts an inline comment
    var i: usize = 0;
    while (i < value.len) : (i += 1) {
        if ((value[i] == ';' or value[i] == '#') and i > 0 and (value[i - 1] == ' ' or value[i - 1] == '\t')) {
            return bun.strings.trim(value[0 .. i - 1], " \t");
        }
    }
    return value;
}

fn coerceValue(globalThis: *jsc.JSGlobalObject, value: []const u8) jsc.JSValue {
    // Empty value -> empty string
    if (value.len == 0) {
        return bun.String.createUTF8ForJS(globalThis, "");
    }

    // Boolean coercion
    if (bun.strings.eqlCaseInsensitiveASCII(value, "true", true)) {
        return JSValue.jsBoolean(true);
    }
    if (bun.strings.eqlCaseInsensitiveASCII(value, "false", true)) {
        return JSValue.jsBoolean(false);
    }

    // Null coercion
    if (bun.strings.eqlCaseInsensitiveASCII(value, "null", true)) {
        return .null;
    }

    // Numeric coercion — try integer then float
    if (std.fmt.parseInt(i64, value, 10)) |int_val| {
        if (int_val >= std.math.minInt(i32) and int_val <= std.math.maxInt(i32)) {
            return JSValue.jsNumber(@as(i32, @intCast(int_val)));
        }
        return JSValue.jsNumber(@as(f64, @floatFromInt(int_val)));
    } else |_| {}

    if (std.fmt.parseFloat(f64, value)) |float_val| {
        return JSValue.jsNumber(float_val);
    } else |_| {}

    // Quoted string — strip quotes
    if (value.len >= 2) {
        const first = value[0];
        const last = value[value.len - 1];
        if ((first == '"' and last == '"') or (first == '\'' and last == '\'')) {
            return bun.String.createUTF8ForJS(globalThis, value[1 .. value.len - 1]);
        }
    }

    // Plain string
    return bun.String.createUTF8ForJS(globalThis, value);
}

pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const arguments = callframe.argumentsAsArray(1);
    const value = arguments[0];

    if (value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    if (!value.isObject()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    // Two-pass approach: first write top-level scalar values, then sections (nested objects)
    var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
        globalThis,
        try value.toObject(globalThis),
    );
    defer iter.deinit();

    // Pass 1: top-level scalars
    while (try iter.next()) |prop_name| {
        const prop_value = iter.value;
        if (prop_value.isObject() and !prop_value.isString() and !prop_value.isNumber() and !prop_value.isBoolean()) {
            // Skip nested objects for now — they'll be handled in pass 2
            continue;
        }
        appendKeyValue(&builder, globalThis, prop_name, prop_value);
    }

    // Pass 2: sections (nested objects)
    iter.reset();
    while (try iter.next()) |prop_name| {
        const prop_value = iter.value;
        if (!prop_value.isObject() or prop_value.isString() or prop_value.isNumber() or prop_value.isBoolean()) {
            continue;
        }

        // Write section header
        builder.append(.lchar, '\n');
        builder.append(.lchar, '[');
        builder.append(.string, prop_name);
        builder.append(.lchar, ']');
        builder.append(.lchar, '\n');

        // Write section properties
        var section_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            globalThis,
            try prop_value.toObject(globalThis),
        );
        defer section_iter.deinit();

        while (try section_iter.next()) |section_key| {
            appendKeyValue(&builder, globalThis, section_key, section_iter.value);
        }
    }

    return builder.toString(globalThis);
}

fn appendKeyValue(builder: *wtf.StringBuilder, globalThis: *jsc.JSGlobalObject, key: bun.String, value: jsc.JSValue) void {
    builder.append(.string, key);
    builder.append(.latin1, " = ");

    if (value.isBoolean()) {
        builder.append(.latin1, if (value.asBoolean()) "true" else "false");
    } else if (value.isNull()) {
        builder.append(.latin1, "null");
    } else if (value.isNumber()) {
        if (value.isInt32()) {
            builder.append(.int, value.asInt32());
        } else {
            builder.append(.double, value.asNumber());
        }
    } else if (value.isString()) {
        const str = value.toBunString(globalThis) catch {
            builder.append(.latin1, "");
            builder.append(.lchar, '\n');
            return;
        };
        defer str.deref();
        builder.append(.string, str);
    } else {
        builder.append(.latin1, "");
    }

    builder.append(.lchar, '\n');
}

